#### Part (b) Model Answer (7 marks):

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class CalculatorApp extends JFrame implements ActionListener {

    JTextField display;
    String operator = "";
    double num1 = 0;
    boolean startNew = true;

    public CalculatorApp() {
        setTitle("Calculator");
        setSize(300, 400);
        setDefaultCloseOperation(EXIT_ON_CLOSE);
        setLayout(new BorderLayout());

        display = new JTextField("0");
        display.setEditable(false);
        display.setFont(new Font("Arial", Font.BOLD, 22));
        display.setHorizontalAlignment(JTextField.RIGHT);
        add(display, BorderLayout.NORTH);

        JPanel panel = new JPanel(new GridLayout(4, 4, 5, 5));
        String[] labels = {"7","8","9","/","4","5","6","*",
                           "1","2","3","-","C","0","=","+"};
        for (String s : labels) {
            JButton b = new JButton(s);
            b.addActionListener(this);
            panel.add(b);
        }
        add(panel, BorderLayout.CENTER);
        setVisible(true);
    }

    public void actionPerformed(ActionEvent e) {
        String c = e.getActionCommand();
        if (c.matches("[0-9]")) {
            if (startNew) { display.setText(c); startNew = false; }
            else display.setText(display.getText() + c);
        } else if (c.equals("C")) {
            display.setText("0"); num1 = 0; operator = ""; startNew = true;
        } else if (c.matches("[+\\-*/]")) {
            num1 = Double.parseDouble(display.getText());
            operator = c;
            startNew = true;
        } else if (c.equals("=")) {
            try {
                double num2 = Double.parseDouble(display.getText());
                double res;
                switch (operator) {
                    case "+": res = num1 + num2; break;
                    case "-": res = num1 - num2; break;
                    case "*": res = num1 * num2; break;
                    case "/":
                        if (num2 == 0)
                            throw new ArithmeticException("Cannot divide by zero");
                        res = num1 / num2; break;
                    default: display.setText("Error"); return;
                }
                display.setText(String.valueOf(res));
                startNew = true;
            } catch (ArithmeticException ex) {
                display.setText("Error: " + ex.getMessage());
                startNew = true;
            }
        }
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> new CalculatorApp());
    }
}
```

**Explanation of key elements (for the 7-mark valuation):**
- `JFrame` is the top-level container; `BorderLayout` places the display on top and the button grid in the center.
- `GridLayout(4,4,5,5)` arranges 16 buttons in a 4×4 grid.
- `implements ActionListener` allows the same class to handle all button clicks via `actionPerformed`.
- The `try-catch` block around the division logic explicitly checks for `num2 == 0` and throws `ArithmeticException` with a meaningful message.
- `SwingUtilities.invokeLater` ensures thread-safe GUI creation on the EDT.

*(Mark distribution: 2 marks constructor + GUI setup, 2 marks listener logic, 1 mark operator handling, 1 mark division check, 1 mark exception handling block.)*

